+		return err
+	}
+	payload := map[string]any{
+		"command": map[string]any{
+			"endpoint": "add_to_queue",
+			"track": map[string]any{
+				"uri": uri,
+			},
+			"logging_params": map[string]any{
+				"command_id": randomHex(32),
+			},
+		},
+	}
+	return c.sendPlayerCommand(ctx, state, "add_to_queue", payload)
+}
